const parts = [$.input.topic];
const staticTerms = "{{}} insights trends linkedin";
return { query: parts.filter(Boolean).join(" ") + " " + staticTerms };

var results = $.steps.researchTopic.response.results || [];
var context = '';
results.slice(0, 8).forEach(function(r, i) {
  context += (i + 1) + '. ' + (r.title || 'Untitled') + '\n   ' + r.url + '\n   ' + (r.text || '').slice(0, 300) + '\n\n';
});
return { context: context, sourceCount: results.length };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { text: raw }; }

var ai = $.steps.parseAI.output;
var now = new Date().toISOString();
var postText = ai.postText || ai.text || '';
var sheetData = [{
  date: now.split('T')[0],
  topic: $.input.topic,
  hook: ai.hook || postText.split('\n')[0] || '',
  postLength: postText.length,
  hashtags: (ai.hashtags || []).join(', '),
  status: 'Published',
  fullPost: postText.slice(0, 500)
}];
return { sheetData: sheetData, postText: postText };

var ai = $.steps.parseAI.output;
var postText = ai.postText || ai.text || '';
var body = 'LinkedIn Post Published

Topic: ' + $.input.topic + '
Date: ' + new Date().toISOString().split('T')[0] + '

--- POST CONTENT ---

' + postText + '

--- END ---

Hashtags: ' + (ai.hashtags || []).join(', ') + '
Estimated read time: ' + (ai.estimatedReadTime || 'N/A') + '
Sources researched: ' + $.steps.compileResearch.output.sourceCount + '

This post was generated and published automatically via One CLI.';
return { subject: 'LinkedIn Post Published: ' + $.input.topic, body: body };
